func (c *connWriter) Init(config string) error {
	res := json.Unmarshal([]byte(config), c)
	if res == nil && len(c.Formatter) > 0 {
		fmtr, ok := GetFormatter(c.Formatter)
		if !ok {
			return fmt.Errorf("the formatter with name: %s not found", c.Formatter)
		}
		c.formatter = fmtr
	}
	return res
}
